/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;
    const sortedNums = [...nums].sort((a, b) => a - b);

    // Helper function to check if a sub-array can be sorted by cyclic shifts
    // A sub-array can be sorted by cyclic shifts if and only if it is a permutation
    // of the sorted version of that sub-array. Since we are only permuting
    // elements within the sub-array, if the sub-array contains the correct set of elements
    // that belong to that segment of the final sorted array, then it *can* be sorted
    // if and only if all elements are distinct or if duplicates are handled correctly.
    // In this problem, since we are comparing against the target sorted array,
    // the set of elements in the segment must match the set of elements in the
    // corresponding segment of sortedNums.
    const canSortSegment = (start, k, targetSegment) => {
        const segment = nums.slice(start, start + k);

        // The key insight is that cyclic shifts only change the order, not the elements present.
        // Therefore, the set of elements in the segment must be identical to the set of elements
        // in the target segment (targetSegment) for sorting to be possible via cyclic shifts.
        // Since we are dealing with multisets (allowing duplicates), we must check if they are permutations.
        const segmentSorted = [...segment].sort((a, b) => a - b);
        for (let i = 0; i < k; i++) {
            if (segmentSorted[i] !== targetSegment[i]) {
                return false;
            }
        }
        return true;
    };

    // Function to check if k is a "sortable integer"
    const isSortable = (k) => {
        if (k === 1) {
            // For k=1, each segment is a single element. Cyclic shift does nothing.
            // If the array is not already sorted, it cannot be sorted.
            for (let i = 0; i < n; i++) {
                if (nums[i] !== sortedNums[i]) {
                    return false;
                }
            }
            return true; // Only true if already sorted
        }

        // Check if all segments can be independently sorted into their target positions
        for (let i = 0; i < n; i += k) {
            const segmentStart = i;
            const segmentLength = k;

            // The target segment in the fully sorted array
            const targetSegment = sortedNums.slice(i, i + k);

            // Check if the current segment in nums is a permutation of the target segment
            if (!canSortSegment(segmentStart, segmentLength, targetSegment)) {
                return false;
            }
        }

        return true;
    };

    let sumK = 0;

    // Find all divisors k of n
    for (let k = 1; k <= n; k++) {
        if (n % k === 0) {
            if (isSortable(k)) {
                sumK += k;
            }
        }
    }

    return sumK;
}

