class Solution {
private:
    // Helper function to check if the multiset of elements in the segment is the same
    // as the multiset of elements in the target segment.
    // This is necessary because cyclic shifts only rearrange elements, they don't change the multiset.
    bool arePermutations(const vector<long long>& segment, const vector<long long>& targetSegment) {
        if (segment.size() != targetSegment.size()) return false;

        vector<long long> sortedSegment = segment;
        vector<long long> sortedTarget = targetSegment;

        sort(sortedSegment.begin(), sortedSegment.end());
        sort(sortedTarget.begin(), sortedTarget.end());

        for (size_t i = 0; i < sortedSegment.size(); ++i) {
            if (sortedSegment[i] != sortedTarget[i]) {
                return false;
            }
        }
        return true;
    }

public:
